parameters.old_string:
export class EventBus {
  private handlers: Map<EventType, EventHandler[]> = new Map();
  private eventLog: AppEvent[] = [];

parameters.new_string:
/**
 * Emit an event to all registered handlers.
 * Emits are serialized: if a previous emit is still being processed,
 * this one queues behind it. This guarantees notification delivery order
 * even when multiple events are emitted without awaiting.
 */
async emit<T extends AppEvent>(event: T): Promise<void> {
  const task = this.emitQueue.then(async () => {
    this.eventLog.push(event);
    const handlers = this.handlers.get(event.type) ?? [];
    for (const handler of handlers) {
      await handler(event);
    }
  });
  // Swallow errors in the queue chain so one failed emit doesn't block subsequent ones
  this.emitQueue = task.catch(() => {});
  return task;
}

