describe('notification ordering', () => {
  it('should deliver notifications in event emission order even when emits are not awaited', async () => {
    const orderCreatedEvent: OrderCreatedEvent = {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ],
        total: 10,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
    };

    const statusChangedEvent: OrderStatusChangedEvent = {
      type: 'order:status-changed',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [],
        total: 10,
        status: 'confirmed',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    // Emit both events WITHOUT awaiting the first — simulates concurrent emission
    const p1 = eventBus.emit(orderCreatedEvent);
    const p2 = eventBus.emit(statusChangedEvent);
    await Promise.all([p1, p2]);

    const notifications = service.getNotifications();

    // order:created notifications (email + webhook) must come before
    // order:status-changed notifications (email + webhook)
    const types = notifications.map((n) => n.type);
    const firstStatusUpdateIndex = types.indexOf('order:status-update');
    const lastConfirmationIndex = types.lastIndexOf('order:confirmation');

    expect(lastConfirmationIndex).toBeLessThan(firstStatusUpdateIndex);
  });
});

